import React, { useState } from 'react';
import api from '../../services/api';
import { FiEdit2, FiTrash2, FiPlus } from 'react-icons/fi';
import { useToast } from '../../context/ToastContext';
import { useConfirm } from '../../context/ConfirmContext';
import useApi from '../../hooks/useApi';
import ColumnSettings from '../../components/common/ColumnSettings';
import ExportButton from '../../components/common/ExportButton';
import ImportButton from '../../components/common/ImportButton';

const AdminJobTitles = () => {
  const [showModal, setShowModal] = useState(false);
  const [edit, setEdit] = useState(null);
  const [form, setForm] = useState({ title: '', description: '', note: '' });
  const toast = useToast();
  const confirm = useConfirm();

  const allColumns = [
    { key: 'title', label: 'Title' },
    { key: 'description', label: 'Description' },
    { key: 'note', label: 'Note' },
    { key: '_actions', label: 'Actions' },
  ];
  const saved = JSON.parse(localStorage.getItem('cols_admin_jobtitles') || 'null');
  const [visibleColumns, setVisibleColumns] = useState(saved || allColumns.map(c => c.key));

  const { data: items, loading, execute: refetch } = useApi(() => api.get('/admin/job-titles'), { immediate: true, showToast: false });

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.title.trim()) return toast.warning('Title is required');
    try {
      if (edit) {
        await api.put(`/admin/job-titles/${edit._id}`, form);
        toast.success('Job title updated');
      } else {
        await api.post('/admin/job-titles', form);
        toast.success('Job title created');
      }
      setShowModal(false); setEdit(null); setForm({ title: '', description: '', note: '' });
      refetch();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Operation failed');
    }
  };

  const handleDelete = async (id, title) => {
    const ok = await confirm(`Delete job title "${title}"? Related employees may be affected.`, 'Delete Job Title');
    if (!ok) return;
    try {
      await api.delete(`/admin/job-titles/${id}`);
      toast.success('Job title deleted');
      refetch();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Delete failed');
    }
  };

  return (
    <div>
      <div className="toolbar">
        <div className="toolbar-right" style={{ marginLeft: 'auto' }}>
          <ColumnSettings columns={allColumns} visibleColumns={visibleColumns} onChange={setVisibleColumns} storageKey="cols_admin_jobtitles" />
          <ExportButton data={items} columns={allColumns} filename="job-titles" visibleColumns={visibleColumns} />
          <ImportButton onImport={(rows) => api.post('/admin/job-titles/import', rows)} columns={allColumns} />
          <button className="btn btn-primary" onClick={() => { setEdit(null); setForm({ title: '', description: '', note: '' }); setShowModal(true); }}><FiPlus /> Add Job Title</button>
        </div>
      </div>
      <div className="card">
        <div className="card-header"><h3>Job Titles</h3></div>
        <div className="card-body">
          <div className="table-container">
            <table>
              <thead><tr>{allColumns.filter(c => visibleColumns.includes(c.key)).map(c => <th key={c.key}>{c.label}</th>)}</tr></thead>
              <tbody>
                {(items || []).map(item => (
                  <tr key={item._id}>
                    {visibleColumns.includes('title') && <td><strong>{item.title}</strong></td>}
                    {visibleColumns.includes('description') && <td>{item.description || '-'}</td>}
                    {visibleColumns.includes('note') && <td>{item.note || '-'}</td>}
                    {visibleColumns.includes('_actions') && <td>
                      <button className="action-btn" onClick={() => { setEdit(item); setForm({ title: item.title, description: item.description, note: item.note }); setShowModal(true); }}><FiEdit2 /></button>
                      <button className="action-btn" onClick={() => handleDelete(item._id, item.title)}><FiTrash2 /></button>
                    </td>}
                  </tr>
                ))}
                {!loading && items?.length === 0 && <tr><td colSpan={visibleColumns.length} style={{ textAlign: 'center', padding: 24, color: '#999' }}>No job titles found</td></tr>}
              </tbody>
            </table>
          </div>
        </div>
      </div>
      {showModal && (
        <div className="modal-backdrop" onClick={() => setShowModal(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header"><h3>{edit ? 'Edit' : 'Add'} Job Title</h3><button className="close-btn" onClick={() => setShowModal(false)}>&times;</button></div>
            <form onSubmit={handleSubmit}>
              <div className="modal-body">
                <div className="form-group"><label>Title</label><input value={form.title} onChange={e => setForm({...form, title: e.target.value})} required /></div>
                <div className="form-group"><label>Description</label><textarea value={form.description} onChange={e => setForm({...form, description: e.target.value})} rows={2} /></div>
                <div className="form-group"><label>Note</label><textarea value={form.note} onChange={e => setForm({...form, note: e.target.value})} rows={2} /></div>
              </div>
              <div className="modal-footer">
                <button type="button" className="btn btn-outline" onClick={() => setShowModal(false)}>Cancel</button>
                <button type="submit" className="btn btn-primary">{edit ? 'Update' : 'Save'}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminJobTitles;
